INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Medicine Ball Overhead Throw', 'medicine-ball-overhead-throw', 'Perform Medicine Ball Overhead Throw with a medicine ball to train overhead force transfer, rib control, and trunk extension-to-flexion timing. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 4, NULL, 75, 95, 'Medicine Ball Overhead Throw is a medicine-ball exercise for overhead force transfer, rib control, and trunk extension-to-flexion timing. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: jump_throw_explosive_power. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Overhead med-ball power', 'output', 'jump_throw_explosive_power', 'med_ball_overhead_throw_power', '{"primary_joint_actions":["shoulder flexion/extension and elbow extension","hip hinge and hip extension","trunk bracing and rib-pelvis control"],"primary_tissues":["pecs","triceps","anterior shoulder","glutes","hamstrings","posterior chain","abdominals","deep core"],"breathing_demand":"brace_then_exhale","balance_demand":"low","coordination_demand":"high","impact_level":1,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"output_profile":{"freshness_required":true,"quality_rule":"every rep must be fast, accurate, and controlled; stop when ball speed or posture drops"}}'::jsonb, '{"movement_description":"Medicine Ball Overhead Throw uses the medicine ball to train overhead force transfer, rib control, and trunk extension-to-flexion timing. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Use a solid wall target and stand far enough away that the ball returns safely, if it returns at all.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Load hips, trunk, and hands into the starting shape.","Throw the ball with maximal intent while keeping the torso organized.","Catch, recover, or collect the ball safely.","Reset posture before the next attempt."],"coach_cues":["Fast ball.","Brace then throw.","Throw through the target.","Reset between reps."],"common_faults":["Choosing a ball too heavy for speed.","Leaking through the ribs or low back.","Over-rotating after release.","Counting slow, inaccurate throws as good reps."]}'::jsonb),
  ('Medicine Ball Rotational Wall Throw', 'medicine-ball-rotational-wall-throw', 'Perform Medicine Ball Rotational Wall Throw with a medicine ball to train hip-to-trunk rotation and high-speed rotational power expression. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 4, NULL, 75, 95, 'Medicine Ball Rotational Wall Throw is a medicine-ball exercise for hip-to-trunk rotation and high-speed rotational power expression. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: jump_throw_explosive_power. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Rotational med-ball power', 'output', 'jump_throw_explosive_power', 'med_ball_rotational_wall_throw_power', '{"primary_joint_actions":["thoracic rotation and hip pivot","shoulder flexion/extension and elbow extension","trunk bracing and rib-pelvis control"],"primary_tissues":["obliques","hips","thoracic spine","pecs","triceps","anterior shoulder","abdominals","deep core"],"breathing_demand":"brace_then_exhale","balance_demand":"moderate","coordination_demand":"high","impact_level":1,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"output_profile":{"freshness_required":true,"quality_rule":"every rep must be fast, accurate, and controlled; stop when ball speed or posture drops"}}'::jsonb, '{"movement_description":"Medicine Ball Rotational Wall Throw uses the medicine ball to train hip-to-trunk rotation and high-speed rotational power expression. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Use a solid wall target and stand far enough away that the ball returns safely, if it returns at all.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Load hips, trunk, and hands into the starting shape.","Throw the ball with maximal intent while keeping the torso organized.","Catch, recover, or collect the ball safely.","Reset posture before the next attempt."],"coach_cues":["Fast ball.","Brace then throw.","Throw through the target.","Reset between reps."],"common_faults":["Choosing a ball too heavy for speed.","Leaking through the ribs or low back.","Over-rotating after release.","Counting slow, inaccurate throws as good reps."]}'::jsonb),
  ('Tall-Kneeling Medicine Ball Chest Pass', 'tall-kneeling-medicine-ball-chest-pass', 'Perform Tall-Kneeling Medicine Ball Chest Pass with a medicine ball to train upper-body throw speed with leg drive removed so trunk stiffness is exposed. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 4, NULL, 75, 95, 'Tall-Kneeling Medicine Ball Chest Pass is a medicine-ball exercise for upper-body throw speed with leg drive removed so trunk stiffness is exposed. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: jump_throw_explosive_power. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Kneeling upper-body power', 'output', 'jump_throw_explosive_power', 'tall_kneeling_med_ball_chest_pass_power', '{"primary_joint_actions":["shoulder flexion/extension and elbow extension","trunk bracing and rib-pelvis control"],"primary_tissues":["pecs","triceps","anterior shoulder","abdominals","deep core","spinal stabilizers"],"breathing_demand":"brace_then_exhale","balance_demand":"low","coordination_demand":"high","impact_level":1,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"output_profile":{"freshness_required":true,"quality_rule":"every rep must be fast, accurate, and controlled; stop when ball speed or posture drops"}}'::jsonb, '{"movement_description":"Tall-Kneeling Medicine Ball Chest Pass uses the medicine ball to train upper-body throw speed with leg drive removed so trunk stiffness is exposed. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Use a solid wall target and stand far enough away that the ball returns safely, if it returns at all.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Load hips, trunk, and hands into the starting shape.","Throw the ball with maximal intent while keeping the torso organized.","Catch, recover, or collect the ball safely.","Reset posture before the next attempt."],"coach_cues":["Fast ball.","Brace then throw.","Throw through the target.","Reset between reps."],"common_faults":["Choosing a ball too heavy for speed.","Leaking through the ribs or low back.","Over-rotating after release.","Counting slow, inaccurate throws as good reps."]}'::jsonb),
  ('Half-Kneeling Medicine Ball Shot-Put Throw', 'half-kneeling-medicine-ball-shot-put-throw', 'Perform Half-Kneeling Medicine Ball Shot-Put Throw with a medicine ball to train single-arm power, split-stance pelvis control, and controlled rotation. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 4, NULL, 75, 95, 'Half-Kneeling Medicine Ball Shot-Put Throw is a medicine-ball exercise for single-arm power, split-stance pelvis control, and controlled rotation. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: jump_throw_explosive_power. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Half-kneeling rotational power', 'output', 'jump_throw_explosive_power', 'half_kneeling_med_ball_shot_put_power', '{"primary_joint_actions":["shoulder flexion/extension and elbow extension","thoracic rotation and hip pivot","trunk bracing and rib-pelvis control"],"primary_tissues":["pecs","triceps","anterior shoulder","obliques","hips","thoracic spine","abdominals","deep core"],"breathing_demand":"brace_then_exhale","balance_demand":"moderate","coordination_demand":"high","impact_level":1,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"output_profile":{"freshness_required":true,"quality_rule":"every rep must be fast, accurate, and controlled; stop when ball speed or posture drops"}}'::jsonb, '{"movement_description":"Half-Kneeling Medicine Ball Shot-Put Throw uses the medicine ball to train single-arm power, split-stance pelvis control, and controlled rotation. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Use a solid wall target and stand far enough away that the ball returns safely, if it returns at all.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Load hips, trunk, and hands into the starting shape.","Throw the ball with maximal intent while keeping the torso organized.","Catch, recover, or collect the ball safely.","Reset posture before the next attempt."],"coach_cues":["Fast ball.","Brace then throw.","Throw through the target.","Reset between reps."],"common_faults":["Choosing a ball too heavy for speed.","Leaking through the ribs or low back.","Over-rotating after release.","Counting slow, inaccurate throws as good reps."]}'::jsonb),
