  ('Slam Ball Ground-to-Shoulder', 'slam-ball-ground-to-shoulder', 'Perform Slam Ball Ground-to-Shoulder with a slam ball to train loaded hip hinge, trunk bracing, and controlled awkward-object strength. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 6, NULL, 75, 90, 'Slam Ball Ground-to-Shoulder is a slam-ball exercise for loaded hip hinge, trunk bracing, and controlled awkward-object strength. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: hinge_posterior_chain_strength. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Ground-to-shoulder strength', 'capacity', 'hinge_posterior_chain_strength', 'slam_ball_ground_to_shoulder_strength', '{"primary_joint_actions":["hip hinge and hip extension","shoulder retraction and elbow flexion","trunk bracing and rib-pelvis control"],"primary_tissues":["glutes","hamstrings","posterior chain","lats","upper back","biceps","abdominals","deep core"],"breathing_demand":"brace_then_exhale","balance_demand":"low","coordination_demand":"moderate","impact_level":1,"implement_profile":{"ball_type":"slam_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."}}'::jsonb, '{"movement_description":"Slam Ball Ground-to-Shoulder uses the slam ball to train loaded hip hinge, trunk bracing, and controlled awkward-object strength. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a slam ball that matches the drill intent and athlete size.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Set the ball close to the body and brace before lifting.","Move through the intended squat, hinge, carry, or clean path with control.","Keep the ball path repeatable and the spine organized.","Rest enough that every rep looks like strength work, not a finisher."],"coach_cues":["Brace first.","Own the load.","Move the ball close.","Same shape every rep."],"common_faults":["Racing the reps.","Losing posture because the ball is too heavy.","Letting the ball drift away from the body.","Turning strength work into sloppy conditioning."]}'::jsonb),
  ('Slam Ball Bear-Hug Squat', 'slam-ball-bear-hug-squat', 'Perform Slam Ball Bear-Hug Squat with a slam ball to train front-loaded leg strength, upright posture, and trunk compression. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 6, NULL, 75, 90, 'Slam Ball Bear-Hug Squat is a slam-ball exercise for front-loaded leg strength, upright posture, and trunk compression. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: squat_knee_dominant_strength. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Bear-hug squat strength', 'capacity', 'squat_knee_dominant_strength', 'slam_ball_bear_hug_squat_strength', '{"primary_joint_actions":["hip/knee flexion and extension","trunk bracing and rib-pelvis control"],"primary_tissues":["quadriceps","glutes","adductors","abdominals","deep core","spinal stabilizers"],"breathing_demand":"brace_then_exhale","balance_demand":"low","coordination_demand":"moderate","impact_level":1,"implement_profile":{"ball_type":"slam_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."}}'::jsonb, '{"movement_description":"Slam Ball Bear-Hug Squat uses the slam ball to train front-loaded leg strength, upright posture, and trunk compression. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a slam ball that matches the drill intent and athlete size.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Set the ball close to the body and brace before lifting.","Move through the intended squat, hinge, carry, or clean path with control.","Keep the ball path repeatable and the spine organized.","Rest enough that every rep looks like strength work, not a finisher."],"coach_cues":["Brace first.","Own the load.","Move the ball close.","Same shape every rep."],"common_faults":["Racing the reps.","Losing posture because the ball is too heavy.","Letting the ball drift away from the body.","Turning strength work into sloppy conditioning."]}'::jsonb),
  ('Slam Ball Bear-Hug Carry', 'slam-ball-bear-hug-carry', 'Perform Slam Ball Bear-Hug Carry with a slam ball to train loaded bracing, footwork, and grip-free trunk compression under movement. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 6, NULL, 75, 90, 'Slam Ball Bear-Hug Carry is a slam-ball exercise for loaded bracing, footwork, and grip-free trunk compression under movement. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: carry_trunk_loaded_bracing_strength. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Bear-hug carry strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'slam_ball_bear_hug_carry', '{"primary_joint_actions":["loaded gait and postural bracing","acceleration/deceleration footwork","trunk bracing and rib-pelvis control"],"primary_tissues":["trunk","upper back","hips","calves","feet","abdominals","deep core","spinal stabilizers"],"breathing_demand":"brace_then_exhale","balance_demand":"moderate","coordination_demand":"moderate","impact_level":1,"implement_profile":{"ball_type":"slam_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."}}'::jsonb, '{"movement_description":"Slam Ball Bear-Hug Carry uses the slam ball to train loaded bracing, footwork, and grip-free trunk compression under movement. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a slam ball that matches the drill intent a