  ('Slam Ball Clean to Front Squat', 'slam-ball-clean-to-front-squat', 'Perform Slam Ball Clean to Front Squat with a slam ball to train ground-to-front-load transition followed by controlled squat strength. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 3, 6, NULL, 75, 90, 'Slam Ball Clean to Front Squat is a slam-ball exercise for ground-to-front-load transition followed by controlled squat strength. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: squat_knee_dominant_strength. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Clean-to-squat strength', 'capacity', 'squat_knee_dominant_strength', 'slam_ball_clean_to_front_squat_strength', '{"primary_joint_actions":["hip hinge and hip extension","hip/knee flexion and extension","trunk bracing and rib-pelvis control"],"primary_tissues":["glutes","hamstrings","posterior chain","quadriceps","adductors","abdominals","deep core","spinal stabilizers"],"breathing_demand":"brace_then_exhale","balance_demand":"low","coordination_demand":"moderate","impact_level":1,"implement_profile":{"ball_type":"slam_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."}}'::jsonb, '{"movement_description":"Slam Ball Clean to Front Squat uses the slam ball to train ground-to-front-load transition followed by controlled squat strength. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a slam ball that matches the drill intent and athlete size.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Set the ball close to the body and brace before lifting.","Move through the intended squat, hinge, carry, or clean path with control.","Keep the ball path repeatable and the spine organized.","Rest enough that every rep looks like strength work, not a finisher."],"coach_cues":["Brace first.","Own the load.","Move the ball close.","Same shape every rep."],"common_faults":["Racing the reps.","Losing posture because the ball is too heavy.","Letting the ball drift away from the body.","Turning strength work into sloppy conditioning."]}'::jsonb),
  ('Slam Ball Sprawl to Slam', 'slam-ball-sprawl-to-slam', 'Perform Slam Ball Sprawl to Slam with a slam ball to train repeatable athletic work under fatigue with clear posture and stop rules. The load, distance, partner input, and volume should preserve the card''s phase intent.', 'INTERMEDIATE', 8, 1, 6, 20, 40, 360, 'Slam Ball Sprawl to Slam is a slam-ball exercise for repeatable athletic work under fatigue with clear posture and stop rules. Use it when that quality is the priority, not as random ball work or fatigue entertainment.', 'Primary subrole: conditioning_intervals. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.', 'Move the ball with intent, own your posture, and reset before the next rep.', 'Slam-ball athletic interval', 'sustained_capacity', 'conditioning_intervals', 'slam_ball_sprawl_to_slam_interval', '{"primary_joint_actions":["acceleration/deceleration footwork","hip hinge and hip extension","shoulder flexion/extension and elbow extension","trunk bracing and rib-pelvis control"],"primary_tissues":["calves","feet","hips","glutes","hamstrings","posterior chain","pecs","triceps"],"breathing_demand":"steady_controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":3,"implement_profile":{"ball_type":"slam_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."}}'::jsonb, '{"movement_description":"Slam Ball Sprawl to Slam uses the slam ball to train repeatable athletic work under fatigue with clear posture and stop rules. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a slam ball that matches the drill intent and athlete size.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Start with the ball and body in a safe athletic position.","Work for the assigned interval while keeping the same mechanics.","Stop immediately if posture, ball path, or landing quality drops.","Rest or rotate stations according to the programmed interval."],"coach_cues":["Quality pace.","Same mechanics tired.","Stop before sloppy.","Breathe under control."],"common_faults":["Chasing exhaustion after form breaks.","Using too much load or too long a work interval.","Letting landings or sprawl mechanics get loud.","Placing conditioning before skill, power, or heavy strength work."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
