  ('step-behind-rotational-slam-ball-slam', 'output', 'step_behind_rotational_slam_ball_slam_power', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('slam-ball-slam-to-sprint-start', 'output', 'slam_ball_slam_to_sprint_start', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('medicine-ball-rebound-slam-to-catch', 'output', 'med_ball_rebound_slam_catch', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('medicine-ball-dead-bug-press', 'prepare_and_access', 'med_ball_dead_bug_press_activation', 5, FALSE, 5, 1, 2, 2, 'low'),
  ('medicine-ball-hollow-body-hold', 'resilience', 'med_ball_hollow_body_hold', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-v-up-pass', 'resilience', 'med_ball_v_up_pass', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-russian-twist-controlled', 'resilience', 'controlled_med_ball_russian_twist', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('tall-kneeling-medicine-ball-chop', 'resilience', 'tall_kneeling_med_ball_chop', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('half-kneeling-medicine-ball-lift', 'resilience', 'half_kneeling_med_ball_lift', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-plank-pull-through', 'resilience', 'med_ball_plank_pull_through', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-rollout', 'resilience', 'med_ball_rollout', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-push-up-hand-switch', 'capacity', 'med_ball_push_up_hand_switch', 5, FALSE, 5, 4, 3, 2, 'moderate_to_high'),
  ('partner-medicine-ball-sit-up-throw', 'resilience', 'partner_med_ball_sit_up_throw', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-chest-pass-catch-and-stick', 'resilience', 'med_ball_chest_pass_catch_and_stick', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-scoop-toss-catch-and-stick', 'resilience', 'med_ball_scoop_toss_catch_and_stick', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('medicine-ball-lateral-shuffle-pass', 'movement_intelligence', 'med_ball_lateral_shuffle_pass', 5, TRUE, 5, 2, 4, 2, 'moderate'),
  ('medicine-ball-catch-to-decel-stick', 'resilience', 'med_ball_catch_to_decel_stick', 5, FALSE, 5, 2, 3, 2, 'moderate'),
  ('reactive-medicine-ball-target-pass', 'movement_intelligence', 'reactive_med_ball_target_pass', 5, TRUE, 5, 2, 4, 2, 'moderate'),
  ('moving-target-medicine-ball-chest-pass', 'movement_intelligence', 'moving_target_med_ball_chest_pass', 5, TRUE, 5, 2, 4, 2, 'moderate'),
  ('medicine-ball-pivot-catch-and-pass', 'movement_intelligence', 'med_ball_pivot_catch_and_pass', 5, TRUE, 5, 2, 4, 2, 'moderate'),
  ('medicine-ball-over-shoulder-track-and-catch', 'movement_intelligence', 'med_ball_over_shoulder_track_and_catch', 5, TRUE, 5, 2, 4, 2, 'moderate'),
  ('partner-trunk-twist-medicine-ball-exchange', 'movement_intelligence', 'partner_trunk_twist_med_ball_exchange', 5, TRUE, 5, 2, 4, 2, 'moderate'),
  ('slam-ball-ground-to-shoulder', 'capacity', 'slam_ball_ground_to_shoulder_strength', 5, FALSE, 5, 4, 3, 2, 'moderate_to_high'),
  ('slam-ball-bear-hug-squat', 'capacity', 'slam_ball_bear_hug_squat_strength', 5, FALSE, 5, 4, 3, 2, 'moderate_to_high'),
  ('slam-ball-bear-hug-carry', 'capacity', 'slam_ball_bear_hug_carry', 5, FALSE, 5, 4, 3, 2, 'moderate_to_high'),
  ('slam-ball-clean-to-front-squat', 'capacity', 'slam_ball_clean_to_front_squat_strength', 5, FALSE, 5, 4, 3, 2, 'moderate_to_high'),
  ('slam-ball-sprawl-to-slam', 'sustained_capacity', 'slam_ball_sprawl_to_slam_interval', 5, FALSE, 5, 5, 3, 2, 'moderate_to_high')
) AS m(slug, phase_key, slot, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

