-- Medicine Balls & Slam Balls cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'medicine_balls_slam_balls_readiness',
  NULL,
  'Medicine-ball and slam-ball work without conditioning drift or wrong phase intent',
  'Throws, slams, catches, trunk control, loaded ball strength, and partner timing must stay phase-honest — high intent and low volume in Output, control in Resilience, strength in Capacity — not random ball work or fatigue entertainment.',
  'Medicine-ball and slam-ball cards span explosive throws and slams, trunk control and anti-rotation, catch-and-decel skill, movement intelligence, partner exchange, loaded ball strength, and controlled late-session repeatability.',
  'Ball drills give immediate feedback on bracing, timing, and force transfer. Poor load choice, short rest, unsafe spacing, or high rep counts after quality fades turn power and skill work into conditioning with higher injury risk.',
  'Place after Prepare & Access and any needed Movement Intelligence; keep volume low and intent high for Output throws/slams; use full rest; stop when ball speed, catch quality, posture, or spacing drops; never use heavy slams or partner drills in unsafe lanes.',
  'Do not program medicine-ball or slam-ball work as a finisher or fatigue circuit; do not choose load that changes the pattern; do not count slow throws or sloppy catches after speed and posture have dropped.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
